#include<bits/stdc++.h>
using namespace std;

int a[200001],b[2000001],c[200001];

int main()
{
	int n,m,i,j;
	scanf("%d%d",&n,&m);
	memset(a,0,sizeof(a));
	for(i=1;i<=m;i++)
	{
		scanf("%d%d",&b[i],&c[i]);
	}
	for(i=1;i<=m;i++)
	{
		for(j=b[i];j<=c[i];j++)
		{
			if(a[j]==0)
			{
				a[j]=1;
			}
			else
			{
				a[j]=0;
			}
		}
	}
	for(i=1;i<=n;i++)
	{
		printf("%d",a[i]);
	}
	return 0;
}
